package main

import (
	"sort"
)

func solve(piles []int64) int64 {
	sort.Ints(piles)
	n := len(piles)
	k := n / 3
	var res int64
	for i := 0; i < k; i++ {
		pos := n - 2 - i*2
		res += piles[pos]
	}
	return res
}
